#!/bin/bash# test-skill-config.sh - 测试技能配置加载set -e  # 遇到错误立即退出echo "🧪 测试技能配置加载..."echo ""# 检查 .env 文件是否存在if [ ! -f ".env" ]; then    echo "❌ 找不到 .env 文件"    exit 1fi# 从 .env 文件加载 SKILLS_CONFIG_JSONexport $(grep "^SKILLS_CONFIG_JSON=" .env | cut -d'=' -f2-)if [ -z "$SKILLS_CONFIG_JSON" ]; then    echo "⚠️  SKILLS_CONFIG_JSON 未设置"    exit 0fiecho "📋 SKILLS_CONFIG_JSON:"echo "$SKILLS_CONFIG_JSON" | python3 -m json.tool 2>/dev/null || echo "$SKILLS_CONFIG_JSON"echo ""# -----------------------------------------------------------------------------# 解析技能配置 JSON 并设置环境变量# 从 SKILLS_CONFIG_JSON 中提取各技能的配置项，转换为独立的环境变量# 例如：jira-diagnosis.baseUrl → JIRA_DIAGNOSIS_BASE_URL#       jira-diagnosis.username → JIRA_DIAGNOSIS_USERNAME# -----------------------------------------------------------------------------parse_skills_config() {    if [ -z "$SKILLS_CONFIG_JSON" ]; then        echo "ℹ️  SKILLS_CONFIG_JSON 未设置"        return    fi    echo "🔧 解析技能配置..."    # 方案：让 node 直接写入文件，然后 source    local exports_file="/tmp/skills_exports_$$.sh"    node -e '    const config = JSON.parse(process.env.SKILLS_CONFIG_JSON);    const fs = require("fs");    const fd = fs.openSync(process.argv[1], "w");    Object.keys(config).forEach(skillName => {        const skillConfig = config[skillName];        const skillPrefix = skillName.toUpperCase().replace(/-/g, "_");        console.error("技能：" + skillName + " (前缀：" + skillPrefix + ")");        Object.keys(skillConfig).forEach(key => {            const envKey = skillPrefix + "_" + key.toUpperCase();            const envValue = String(skillConfig[key]);            // 单引号包裹，避免转义问题            const line = "export " + envKey + "='\''" + envValue + "'\''\n";            fs.writeSync(fd, line);            console.error("  ✓ " + envKey + "=" + envValue);        });    });    fs.closeSync(fd);    ' "$exports_file"    # 执行生成的脚本    source "$exports_file"    rm -f "$exports_file"    echo "✅ 完成"}# 执行解析parse_skills_config# 显示当前 shell 中可用的环境变量echo "📊 当前 Shell 中的技能环境变量:"echo "========================================"env | grep -E "^(JIRA_|SKILLS_)" | sortecho "========================================"echo ""# 验证特定变量是否已设置echo "🔍 验证关键环境变量:"if [ -n "$JIRA_DIAGNOSIS_BASEURL" ]; then    echo "✅ JIRA_DIAGNOSIS_BASEURL = $JIRA_DIAGNOSIS_BASEURL"else    echo "❌ JIRA_DIAGNOSIS_BASEURL 未设置"fiif [ -n "$JIRA_DIAGNOSIS_USERNAME" ]; then    echo "✅ JIRA_DIAGNOSIS_USERNAME = $JIRA_DIAGNOSIS_USERNAME"else    echo "❌ JIRA_DIAGNOSIS_USERNAME 未设置"fiif [ -n "$JIRA_DIAGNOSIS_PASSWORD" ]; then    echo "✅ JIRA_DIAGNOSIS_PASSWORD = **** (已隐藏)"else    echo "❌ JIRA_DIAGNOSIS_PASSWORD 未设置"fiif [ -n "$JIRA_DIAGNOSIS_DEFAULTPROJECT" ]; then    echo "✅ JIRA_DIAGNOSIS_DEFAULTPROJECT = $JIRA_DIAGNOSIS_DEFAULTPROJECT"else    echo "❌ JIRA_DIAGNOSIS_DEFAULTPROJECT 未设置"fiecho ""echo "💡 提示:"echo "   这些环境变量将在容器启动时由 init.sh 自动设置"echo "   技能代码可以通过 process.env.JIRA_DIAGNOSIS_XXX 读取"echo ""echo "🧪 测试完成!"